const stalled = $('Find stalled tasks').all().map(i => i.json).filter(r => r.memo_id);
const failures = $('Find recent failures').all().map(i => i.json).filter(r => r.workflow_name);

const issues = [];

// Classify stalled tasks
for (const t of stalled) {
    const hours = parseFloat(t.hours_open) || 0;
    const severity = hours > 12 ? 'critical' : hours > 4 ? 'high' : 'medium';
    issues.push({
        type: 'stalled_task', severity, memo_id: t.memo_id,
        from_agent: t.from_agent, to_agent: t.to_agent,
        subject: t.subject, hours_open: hours,
        fix: t.memo_type === 'cto_review_request' ? 'cto_nudge' : 'cos_escalate'
    });
}

// Classify repeated failures
const wfFailMap = {};
for (const f of failures) {
    wfFailMap[f.workflow_name] = (wfFailMap[f.workflow_name] || 0) + 1;
}
for (const [wf, count] of Object.entries(wfFailMap)) {
    if (count >= 2) {
        issues.push({
            type: 'repeated_failure', severity: count >= 5 ? 'critical' : 'high',
            workflow_name: wf, failure_count: count,
            fix: 'cto_architecture_review'
        });
    }
}

const critical = issues.filter(i => i.severity === 'critical');
const high = issues.filter(i => i.severity === 'high');
const total = issues.length;

if (total === 0) return [{ json: { no_issues: true } }];

return [{ json: { issues, critical_count: critical.length, high_count: high.length,
    summary: `${total} issues: ${critical.length} critical, ${high.length} high` } }];
